integrate Firebase Google Analytics for both Android and iOS builds of my app.

For Android:

Place google-services.json in the Android /app directory.

Enable the Google Services Gradle Plugin:

In project-level build.gradle.kts
plugins {
    id("com.google.gms.google-services") version "4.4.3" apply false
}

In app-level build.gradle.kts
plugins {
    id("com.google.gms.google-services")
}

Add the Firebase Analytics dependency:
implementation("com.google.firebase:firebase-analytics")
Ensure Firebase initializes on app start so Analytics sends events.

For iOS:

Add GoogleService-Info.plist to the Xcode project root and include it in the main app target.

Install FirebaseAnalytics using Swift Package Manager or CocoaPods:
pod 'Firebase/Analytics'

Initialize Firebase in the app’s entry point:

For SwiftUI template:
import FirebaseCore
class AppDelegate: NSObject, UIApplicationDelegate {
    func application(_ application: UIApplication,
        didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        FirebaseApp.configure()
        return true
    }
}
@main
struct YourApp: App {
    @UIApplicationDelegateAdaptor(AppDelegate.self) var delegate
    var body: some Scene {
        WindowGroup {
            ContentView()
        }
    }
}

Or use the standard AppDelegate method if not SwiftUI.
